filldraw(shift(sqrt(3)*2,3)*hex,lightcolor,black);
filldraw(shift(sqrt(3)*1.5,4.5)*hex,lightcolor,black);
filldraw(shift(sqrt(3)*.5,4.5)*hex,lightcolor,black);
filldraw(shift(0,3)*hex,lightcolor,black);
[/asy]

